"""Вкладка «Графики».Canvas заполняет всю доступную площадь вкладки (Expanding + widgetResizable).Figure автоматически подстраивается под размер canvas.Плитки не растягиваются бесконтрольно: отступы subplots_adjust зависятот числа столбцов — при малом числе фильтров увеличиваются боковые margin,чтобы плитки оставались компактными по ширине."""from __future__ import annotationsimport mathimport numpy as npfrom matplotlib.backends.backend_qtagg import (    FigureCanvasQTAgg as FigureCanvas,    NavigationToolbar2QT as NavigationToolbar,)from matplotlib.figure import Figurefrom matplotlib.gridspec import GridSpecfrom PySide6.QtWidgets import QSizePolicy, QVBoxLayout, QWidgetfrom ...core.aggregation import average_signalsfrom ...core.types import ExperimentResult, ExperimentSeries# Зазоры (доли subplot-area)._INNER_HSPACE = 0.30_OUTER_HSPACE = 0.35_OUTER_WSPACE = 0.32# Минимальная высота canvas в пикселях на одну строку блоков._MIN_ROW_PX = 300_MIN_SUPTITLE_PX = 36# Шрифты._FONT_BLOCK_TITLE = 9_FONT_SUPTITLE = 9_FONT_YLABEL = 7_FONT_XLABEL = 7_FONT_TICK = 6# Максимальная доля ширины figure, которую занимают subplot-ы,# в зависимости от числа столбцов. Остальное — боковые отступы.# Это не даёт 1–2 плиткам растянуться на всё окно._MAX_SUBPLOT_WIDTH_FRAC: dict[int, float] = {    1: 0.42,   # 1 плитка ≈ 42% ширины окна    2: 0.72,   # 2 плитки ≈ 72%    3: 0.92,   # 3 плитки ≈ 92% (почти всё окно)}class PlotTab(QWidget):    def __init__(self, parent: QWidget | None = None) -> None:        super().__init__(parent)        self._figure = Figure()        self._canvas = FigureCanvas(self._figure)        self._canvas.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)        self._toolbar = NavigationToolbar(self._canvas, self)        lay = QVBoxLayout(self)        lay.setContentsMargins(0, 0, 0, 0)        lay.setSpacing(0)        lay.addWidget(self._toolbar)        lay.addWidget(self._canvas, 1)        self._current_rows = 1        self._current_cols = 1        self._init_placeholder()    # ---------- публичный API ------------------------------------------------    def display_series(self, series: ExperimentSeries) -> None:        fnames = list(series.filter_names)        n = len(fnames)        if n == 0:            self._init_placeholder()            return        rows, cols = _grid_shape(n)        self._current_rows = rows        self._current_cols = cols        self._figure.clear()        # Минимальная высота canvas — прокрутка не нужна, но плитки не плоские.        min_h = rows * _MIN_ROW_PX + _MIN_SUPTITLE_PX        self._canvas.setMinimumHeight(min_h)        gs_outer = GridSpec(            rows, cols,            figure=self._figure,            hspace=_OUTER_HSPACE,            wspace=_OUTER_WSPACE,        )        for idx, fname in enumerate(fnames):            r, c = divmod(idx, cols)            inner = gs_outer[r, c].subgridspec(3, 1, hspace=_INNER_HSPACE)            ax_clean = self._figure.add_subplot(inner[0, 0])            ax_noisy = self._figure.add_subplot(inner[1, 0], sharex=ax_clean)            ax_rest  = self._figure.add_subplot(inner[2, 0], sharex=ax_clean)            runs = series.results.get(fname, [])            if not runs:                for ax in (ax_clean, ax_noisy, ax_rest):                    ax.text(0.5, 0.5, "нет данных",                            ha="center", va="center", transform=ax.transAxes)                    ax.grid(True, alpha=0.3)                ax_clean.set_title(fname, fontsize=_FONT_BLOCK_TITLE)                continue            avg = average_signals(runs)            t = avg["t"]            ax_clean.set_title(fname,                               fontsize=_FONT_BLOCK_TITLE, loc="left", pad=3)            ax_clean.plot(t, avg["clean_mean"], lw=0.9, color="black")            ax_clean.set_ylabel("clean", fontsize=_FONT_YLABEL)            n_runs = len(runs)            noisy_lbl = "noisy" if n_runs == 1 else f"noisy (ср.{n_runs})"            ax_noisy.plot(t, avg["noisy_mean"], lw=0.8, color="tab:orange")            ax_noisy.set_ylabel(noisy_lbl, fontsize=_FONT_YLABEL)            rest_lbl = "restored" if n_runs == 1 else f"restored (ср.{n_runs})"            ax_rest.plot(t, avg["restored_mean"], lw=1.0, color="tab:green")            ax_rest.set_ylabel(rest_lbl, fontsize=_FONT_YLABEL)            ax_rest.set_xlabel("t, с", fontsize=_FONT_XLABEL)            for ax in (ax_clean, ax_noisy, ax_rest):                ax.grid(True, alpha=0.3)                ax.margins(x=0)                ax.tick_params(axis="both", labelsize=_FONT_TICK)            ax_clean.tick_params(axis="x", labelbottom=False)            ax_noisy.tick_params(axis="x", labelbottom=False)        self._apply_margins(cols)        self._figure.suptitle(            f"Сигнал: {series.signal_name}   |   "            f"Шум: {series.noise_name}   |   "            f"Испытаний: {series.n_trials}",            fontsize=_FONT_SUPTITLE, y=0.98,        )        self._canvas.draw_idle()    def display_result(self, result: ExperimentResult) -> None:        self._figure.clear()        self._current_rows = 1        self._current_cols = 1        self._canvas.setMinimumHeight(_MIN_ROW_PX + _MIN_SUPTITLE_PX)        gs = GridSpec(3, 1, figure=self._figure, hspace=_INNER_HSPACE)        ax_clean = self._figure.add_subplot(gs[0, 0])        ax_noisy = self._figure.add_subplot(gs[1, 0], sharex=ax_clean)        ax_rest  = self._figure.add_subplot(gs[2, 0], sharex=ax_clean)        ax_clean.set_title(result.filter_name,                           fontsize=_FONT_BLOCK_TITLE, loc="left", pad=3)        ax_clean.plot(result.clean.t, result.clean.x, lw=0.9, color="black")        ax_clean.set_ylabel("clean", fontsize=_FONT_YLABEL)        ax_noisy.plot(result.noisy.t, result.noisy.x, lw=0.8, color="tab:orange")        ax_noisy.set_ylabel("noisy", fontsize=_FONT_YLABEL)        ax_rest.plot(result.restored.t, result.restored.x, lw=1.0, color="tab:green")        ax_rest.set_ylabel("restored", fontsize=_FONT_YLABEL)        ax_rest.set_xlabel("t, с", fontsize=_FONT_XLABEL)        for ax in (ax_clean, ax_noisy, ax_rest):            ax.grid(True, alpha=0.3)            ax.margins(x=0)            ax.tick_params(axis="both", labelsize=_FONT_TICK)        ax_clean.tick_params(axis="x", labelbottom=False)        ax_noisy.tick_params(axis="x", labelbottom=False)        self._apply_margins(1)        self._figure.suptitle(            f"Сигнал: {result.signal_name}   |   Шум: {result.noise_name}",            fontsize=_FONT_SUPTITLE, y=0.98,        )        self._canvas.draw_idle()    def clear(self) -> None:        self._init_placeholder()    # ---------- internals ----------------------------------------------------    def _apply_margins(self, cols: int) -> None:        """Отступы subplots_adjust: боковые margin зависят от числа столбцов."""        frac = _MAX_SUBPLOT_WIDTH_FRAC.get(cols, 0.92)        side = (1.0 - frac) / 2.0        self._figure.subplots_adjust(            left=max(side, 0.04),            right=min(1.0 - side, 0.98),            top=0.90,            bottom=0.07,        )    def _init_placeholder(self) -> None:        self._figure.clear()        self._current_rows = 1        self._current_cols = 1        self._canvas.setMinimumHeight(0)        ax = self._figure.add_subplot(1, 1, 1)        ax.set_title("Графики (выполните моделирование)", fontsize=10)        ax.grid(True, alpha=0.3)        self._canvas.draw_idle()def _grid_shape(n: int) -> tuple[int, int]:    """Адаптивная сетка.    1   → 1×1    2   → 1×2    3–4 → 2×2    5–6 → 2×3    7–9 → 3×3    """    if n <= 0:        return 1, 1    if n == 1:        return 1, 1    if n == 2:        return 1, 2    cols = min(3, int(math.ceil(math.sqrt(n))))    rows = int(math.ceil(n / cols))    return rows, cols